    41→func TestFetch_Download(t *testing.T) {
    42→	skipIfNoXZ(t)
    43→
    44→	want := "col1,col2\nval1,val2\n"
    45→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    46→		w.Header().Set("ETag", `"abc123"`)
    47→		w.WriteHeader(http.StatusOK)
    48→		_, _ = w.Write([]byte(want))
    49→	}))
    50→	defer srv.Close()
    51→
    52→	dir := t.TempDir()
    53→	f := fetch.New(dir)
    54→	cfg := fetch.FetchConfig{Name: "test", URL: srv.URL, Format: "csv"}
    55→
    56→	rc, err := f.Fetch(context.Background(), cfg)
    57→	if err != nil {
    58→		t.Fatalf("Fetch: %v", err)
    59→	}
    60→	defer rc.Close()
    61→
    62→	got, err := io.ReadAll(rc)
    63→	if err != nil {
    64→		t.Fatalf("ReadAll: %v", err)
    65→	}
    66→	if string(got) != want {
    67→		t.Errorf("content: got %q, want %q", got, want)
    68→	}
    69→
    70→	// Verify archive was created.
    71→	matches, _ := filepath.Glob(filepath.Join(dir, "test-*.csv.xz"))
    72→	if len(matches) == 0 {
    73→		t.Error("no .xz archive created in cache dir")
    74→	}
    75→
    76→	// Verify sidecar was created.
    77→	if _, err := os.Stat(filepath.Join(dir, "test.cache.json")); err != nil {
    78→		t.Error("sidecar JSON not created")
    79→	}
    80→}
