    82→func TestFetch_Conditional304(t *testing.T) {
    83→	skipIfNoXZ(t)
    84→
    85→	want := "col1,col2\nrow1\n"
    86→	callCount := 0
    87→
    88→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    89→		callCount++
    90→		if r.Header.Get("If-None-Match") == `"etag1"` {
    91→			w.WriteHeader(http.StatusNotModified)
    92→			return
    93→		}
    94→		w.Header().Set("ETag", `"etag1"`)
    95→		w.WriteHeader(http.StatusOK)
    96→		_, _ = w.Write([]byte(want))
    97→	}))
    98→	defer srv.Close()
    99→
   100→	dir := t.TempDir()
   101→	f := fetch.New(dir)
   102→	cfg := fetch.FetchConfig{Name: "cond", URL: srv.URL, Format: "csv"}
   103→
   104→	// First fetch — downloads and caches.
   105→	rc1, err := f.Fetch(context.Background(), cfg)
   106→	if err != nil {
   107→		t.Fatalf("first Fetch: %v", err)
   108→	}
   109→	rc1.Close()
   110→
   111→	if callCount != 1 {
   112→		t.Errorf("expected 1 HTTP call after first fetch, got %d", callCount)
   113→	}
   114→
   115→	// Second fetch — server returns 304; should reuse cached file.
   116→	rc2, err := f.Fetch(context.Background(), cfg)
   117→	if err != nil {
   118→		t.Fatalf("second Fetch: %v", err)
   119→	}
   120→	defer rc2.Close()
   121→
   122→	got, _ := io.ReadAll(rc2)
   123→	if string(got) != want {
   124→		t.Errorf("304 content: got %q, want %q", got, want)
   125→	}
   126→	if callCount != 2 {
   127→		t.Errorf("expected 2 HTTP calls total, got %d", callCount)
   128→	}
   129→}
