   170→func TestFetch_ManualDrop(t *testing.T) {
   171→	skipIfNoXZ(t)
   172→
   173→	content := "manual,drop\ndata,here\n"
   174→	dir := t.TempDir()
   175→
   176→	// Manually place an xz-compressed file in the cache directory.
   177→	xzPath := filepath.Join(dir, "manual-2026-01-01.csv.xz")
   178→	if err := os.WriteFile(xzPath, makeXZ(t, content), 0o644); err != nil {
   179→		t.Fatalf("write manual xz: %v", err)
   180→	}
   181→
   182→	// Fetcher should use the manually-dropped file without hitting the network.
   183→	called := false
   184→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
   185→		called = true
   186→		w.WriteHeader(http.StatusOK)
   187→		_, _ = w.Write([]byte("should not be reached"))
   188→	}))
   189→	defer srv.Close()
   190→
   191→	f := fetch.New(dir)
   192→	cfg := fetch.FetchConfig{Name: "manual", URL: srv.URL, Format: "csv"}
   193→
   194→	rc, err := f.Fetch(context.Background(), cfg)
   195→	if err != nil {
   196→		t.Fatalf("Fetch: %v", err)
   197→	}
   198→	defer rc.Close()
   199→
   200→	if called {
   201→		t.Error("HTTP server was called despite manual-drop file being present")
   202→	}
   203→
   204→	got, _ := io.ReadAll(rc)
   205→	if string(got) != content {
   206→		t.Errorf("manual drop content: got %q, want %q", got, content)
   207→	}
   208→}
