   210→func TestFetch_GzipSource(t *testing.T) {
   211→	skipIfNoXZ(t)
   212→
   213→	want := "col1,col2\ngzip,data\n"
   214→
   215→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
   216→		var buf bytes.Buffer
   217→		gw := gzip.NewWriter(&buf)
   218→		_, _ = gw.Write([]byte(want))
   219→		gw.Close()
   220→		w.Header().Set("Content-Type", "application/gzip")
   221→		w.WriteHeader(http.StatusOK)
   222→		_, _ = w.Write(buf.Bytes())
   223→	}))
   224→	defer srv.Close()
   225→
   226→	dir := t.TempDir()
   227→	f := fetch.New(dir)
   228→	cfg := fetch.FetchConfig{Name: "gzipped", URL: srv.URL, Format: "csv.gz"}
   229→
   230→	rc, err := f.Fetch(context.Background(), cfg)
   231→	if err != nil {
   232→		t.Fatalf("Fetch: %v", err)
   233→	}
   234→	defer rc.Close()
   235→
   236→	got, _ := io.ReadAll(rc)
   237→	if string(got) != want {
   238→		t.Errorf("gzip content: got %q, want %q", got, want)
   239→	}
   240→
   241→	// Should be archived as .csv.xz (gzip wrapper stripped).
   242→	matches, _ := filepath.Glob(filepath.Join(dir, "gzipped-*.csv.xz"))
   243→	if len(matches) == 0 {
   244→		t.Error("expected gzipped-*.csv.xz archive, none found")
   245→	}
   246→}
