package namematch

import (
	"strings"
	"unicode"

	"golang.org/x/text/runes"
	"golang.org/x/text/transform"
	"golang.org/x/text/unicode/norm"
)

// Normalize returns a canonical form of an institution name suitable for
// fuzzy matching. It lowercases, strips diacritics, removes a leading "the ",
// strips punctuation, and collapses whitespace.
func Normalize(s string) string {
	s = strings.ToLower(s)

	// Strip diacritics via NFD decomposition → remove non-spacing marks → NFC
	t := transform.Chain(norm.NFD, runes.Remove(runes.In(unicode.Mn)), norm.NFC)
	stripped, _, err := transform.String(t, s)
	if err == nil {
		s = stripped
	}

	// Remove leading "the "
	s = strings.TrimPrefix(s, "the ")

	// Replace punctuation / non-alphanumeric (except spaces) with a space
	var b strings.Builder
	b.Grow(len(s))
	for _, r := range s {
		if unicode.IsLetter(r) || unicode.IsDigit(r) || r == ' ' {
			b.WriteRune(r)
		} else {
			b.WriteRune(' ')
		}
	}
	s = b.String()

	// Collapse runs of whitespace
	fields := strings.Fields(s)
	return strings.Join(fields, " ")
}

